// 1) Parse AMQP body (Buffer -> JSON)
 let data = msg.payload;

 if (msg.content) {
 const text = msg.content.toString("utf8");
 try {
 data = JSON.parse(text);
 } catch (e) {

 const rawMsg = { ...msg, payload: { raw: text } };

 return [rawMsg, null];
 }
 }
 // 2) Flat notification payload
 const rec = (data.Records && data.Records[0]) ? data.Records[0] : {};

 const flat = {
 event: data.EventName || rec.eventName || "unknown",
 objectKey: data.Key || (rec.s3 && rec.s3.object && rec.s3.object.key) || "unknown",
 bucket: (rec.s3 && rec.s3.bucket && rec.s3.bucket.name) || "unknown",
 size: (rec.s3 && rec.s3.object && rec.s3.object.size) || 0,
 eventTime: rec.eventTime || new Date().toISOString()
 };


 const rawMsg = { ...msg, payload: flat };


 const dlMsg = { ...msg, payload: flat };

 return [rawMsg, dlMsg];

const expectedSecret = "supersecret123";
const receivedSecret = msg.req?.headers?.["x-event-secret"];


let event = msg.payload;

if (typeof event === "string") {
    try { event = JSON.parse(event); } catch(e) {}
}

if (receivedSecret !== expectedSecret) {
    msg.statusCode = 401;
    msg.payload = { error: "Unauthorized" };
    return msg;
}

if (!event || !event.event_type) {
    msg.statusCode = 400;
    msg.payload = { error: "Invalid payload" };
    return msg;
}

msg.statusCode = 200;
msg.event = event;              
msg.payload = { status: "ok" }; 
return [msg, msg];

/**
 * Function node: build_s3_object
 * Outputs:
 *  1) Upload message for amazon s3 out (MinIO)
 */

if (typeof msg.payload === "string") {
  try {
    msg.payload = JSON.parse(msg.payload);
  } catch (e) {
    msg.statusCode = 400;
    msg.payload = { error: "Invalid JSON payload" };
    return null;
  }
}

const e = msg.event || msg.payload;

if (!e || typeof e !== "object") {
  msg.statusCode = 400;
  msg.payload = { error: "Missing event object" };
  return null;
}

const now = new Date();
const yyyy = now.getFullYear();
const mm = String(now.getMonth() + 1).padStart(2, "0");
const dd = String(now.getDate()).padStart(2, "0");
const ts = now.toISOString().replace(/[:.]/g, "-");

const type = e.event_type || "unknown";
const user =
  e.user?.username ||
  e.order?.user?.username ||
  "anonymous";

const key = `${type}/${yyyy}/${mm}/${dd}/${ts}_${user}.json`;

msg.payload = JSON.stringify(e);
msg.key = key;
msg.filename = key;
msg.objectKey = key;
msg.s3 = { key: key };

return msg;

const bucket = msg.payload.bucket;
let key = msg.payload.objectKey;


if (key && bucket && key.startsWith(bucket + "/")) {
    key = key.slice((bucket + "/").length);
}


if (key) {
    try {
        key = decodeURIComponent(key.replace(/\+/g, '%20'));
    } catch (e) {
        // ignore
    }
}

msg.minio = { bucket, key };
return msg;

// function: filter_only_object_created
const ev = msg.payload?.event || "";


if (!ev.startsWith("s3:ObjectCreated:")) {

  return null;
}

return msg;

let order = msg.payload;

// Αν έρθει ως string, κάνε parse
if (typeof order === "string") {
    order = JSON.parse(order);
}

let items = order.items || order.line_items || [];

msg.payload = {
    event_type: order.event_type || "order_created",
    source: order.source || "order-api",

    order_id: order.id || null,
    woocommerce_order_id: order.woocommerce_order_id || order.id || null,

    status: order.status || "unknown",

    customer: order.customer_name || 
              ((order.billing?.first_name || "") + " " + (order.billing?.last_name || "")).trim() || 
              "unknown",

    email: order.customer_email || order.billing?.email || "unknown",

    product: order.product || (items[0] ? items[0].name : "unknown"),
    quantity: order.quantity || (items[0] ? items[0].quantity : 0),

    total: parseFloat(order.total || 0),
    currency: order.currency || "EUR",

    items_count: items.length || (order.quantity ? 1 : 0),

    created_at: order.created_at || new Date().toISOString()
};

return msg;

const ev = msg.payload || {};
const minio = msg.minio || {};

const objectKey = minio.key || ev.objectKey || "unknown";
const bucket = minio.bucket || ev.bucket || "unknown";

const parts = objectKey.split("/");
const businessEventType = parts[0] || "unknown";

const filename = parts[parts.length - 1] || "";
let username = "unknown";

const match = filename.match(/_([^_]+)\.json$/);
if (match) username = match[1];

let cartItems = ev.cart_items || ev.cart_total_qty || 0;
let orderItems = ev.order_items || ev.order_total_qty || 0;

let message = `Event ${businessEventType} από ${username}`;

if (businessEventType === "cart_add") {
  message = `Ο χρήστης ${username} έβαλε προϊόν στο καλάθι. Σύνολο προϊόντων στο καλάθι: ${cartItems}`;
}

if (businessEventType === "order_created") {
  message = `Ο χρήστης ${username} αγόρασε ${orderItems || 1} προϊόν`;
}

msg.payload = {
  source: "minio",
  business_event_type: businessEventType,
  username: username,
  cart_items: cartItems,
  order_items: orderItems,
  message: message,
  bucket: bucket,
  object_key: objectKey,
  event_time: ev.eventTime || new Date().toISOString()
};

return msg;

const ev = msg.event || msg.payload || {};
const type = ev.event_type || "unknown";
const username = ev.user?.username || "unknown";

function countItems(items) {
  if (!Array.isArray(items)) return 0;
  return items.reduce((sum, item) => sum + (Number(item.qty) || 0), 0);
}

const cartItems = countItems(ev.cart?.items);
const orderItems = countItems(ev.order?.items);

let message = `Ο χρήστης ${username} έκανε event ${type}`;

if (type === "login") {
  message = `Ο χρήστης ${username} συνδέθηκε στο e-shop`;
}

if (type === "cart_add") {
  message = `Ο χρήστης ${username} έβαλε προϊόν στο καλάθι. Σύνολο προϊόντων στο καλάθι: ${cartItems}`;
}

if (type === "order_created") {
  message = `Ο χρήστης ${username} αγόρασε ${orderItems} προϊόν`;
}

msg.headers = {
  "Content-Type": "application/json"
};

msg.payload = {
  source: "wordpress",
  username: username,
  business_event_type: type,
  cart_items: cartItems,
  order_items: orderItems,
  message: message,
  event_time: new Date().toISOString()
};

return msg;
